import{_ as t,o,c as n,a3 as a}from"./chunks/framework.CjquFG0V.js";const y=JSON.parse('{"title":"5. Notice Of Termination Employer","description":"","frontmatter":{"title":"5. Notice Of Termination Employer","eba":"Health Allied & Managers Admin 2021-2025","topics":["employment","termination"]},"headers":[],"relativePath":"ebas/has-managers-admin/health-allied-services/employment-types/5-notice-of-termination-employer.md","filePath":"ebas/has-managers-admin/health-allied-services/employment-types/5-notice-of-termination-employer.md"}'),i={name:"ebas/has-managers-admin/health-allied-services/employment-types/5-notice-of-termination-employer.md"};function r(s,e,m,p,l,h){return o(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="_5-notice-of-termination-employer" tabindex="-1">5. Notice Of Termination Employer <a class="header-anchor" href="#_5-notice-of-termination-employer" aria-label="Permalink to &quot;5. Notice Of Termination Employer&quot;">​</a></h1><p><strong>5.1</strong> The Employer must not terminate an Employee’s employment unless they have given the Employee written notice of the day of the termination (which cannot be before the day the notice is given).</p><p><strong>(a)</strong> In order to terminate the employment of an Employee, the Employer must give the minimum period of notice based on the Employee’s period of continuous service with the Employer up to the end of the day the notice is given, as follows: Period of continuous service Period of Notice</p><p>Not more than 1 year 1 week</p><p>More than 1 year but not more than 3 2 weeks years</p><p>More than 3 years but not more than 5 3 weeks years</p><p>More than 5 years 4 weeks</p><p><strong>(b)</strong> The period of notice in subclause 5.1(a) will be increased by one week if the Employee is over 45 years of age and has completed at least 2 years continuous service with the Employer at the end of the day the notice is given.</p><p><strong>5.2</strong> Where an Employer has given notice of termination to an Employee, the Employee must be allowed time off without loss of pay of up to one day for the purpose of seeking other employment. The time off under this subclause 5.2 is to be taken at times that are convenient to the Employee after consultation with the Employer.</p><p>Plain language terms: notice period, dismissal notice.</p>',10)])])}const d=t(i,[["render",r]]);export{y as __pageData,d as default};
